13.query:
fetch dt.davis.problems
//| filterOut event.category == "CUSTOM_ALERT"
//| fields event.start, affected_entity_types, event.category, event.name, event.description
| makeTimeseries {problems=count(default:0), root_cause=countIf(isNotNull(root_cause_entity_id)), mttr=avg(resolved_problem_duration)}, by:{event.name, event.category}, interval:1d
| fieldsAdd total=arraySum(problems), root_cause.total=arraySum(root_cause), mttr.avg=arrayAvg(mttr)
| sort total desc
| lookup [
  fetch dt.davis.problems
  | summarize {event.id=takeLast(event.id)}, by:{event.name}
], sourceField:event.name, lookupField:event.name
| fieldsAdd percent_root_cause=100*root_cause.total/total,lastInstance=concat("[](https://", $environmentId, ".apps.dynatrace.com/ui/apps/dynatrace.davis.problems/problem/", lookup.event.id,")")
| fieldsAdd percent_root_cause=if(in(event.name,$root_cause_exempt), "N/A", else:percent_root_cause)
